import sqlite3
import os
import json
from collections import defaultdict

# Hex grid utilities for offset coordinates (odd-r)
def get_hex_neighbors(x, y):
    if y % 2 == 1:
        return [(x+1, y), (x+1, y-1), (x+1, y+1), (x-1, y), (x, y-1), (x, y+1)]
    else:
        return [(x+1, y), (x, y-1), (x, y+1), (x-1, y), (x-1, y-1), (x-1, y+1)]

def hex_distance(x1, y1, x2, y2):
    def to_cube(x, y):
        if y % 2 == 1:
            x_cube = x - (y - 1) // 2
        else:
            x_cube = x - y // 2
        return x_cube, y, -x_cube - y
    cx1, cy1, cz1 = to_cube(x1, y1)
    cx2, cy2, cz2 = to_cube(x2, y2)
    return max(abs(cx1 - cx2), abs(cy1 - cy2), abs(cz1 - cz2))

def get_tiles_in_range(cx, cy, max_dist):
    result = []
    for dy in range(-max_dist, max_dist + 1):
        for dx in range(-max_dist, max_dist + 1):
            x, y = cx + dx, cy + dy
            if hex_distance(cx, cy, x, y) <= max_dist:
                result.append((x, y))
    return result

# Load map
dbpath = None
for f in os.listdir('/data/maps'):
    fp = '/data/maps/' + f
    if os.path.getsize(fp) > 0:
        dbpath = fp
        break

