for row in cursor.fetchall():
    pid = row[0]
    x, y = pid % width, pid // width
    if (x, y) in plots:
        plots[(x, y)]['has_river'] = True

print(f"Map: {width}x{height}")
print(f"Loaded {len(plots)} tiles")

# Find valid city center locations
valid_city_tiles = []
for (x, y), tile in plots.items():
    if tile['terrain'] not in ['TERRAIN_OCEAN'] and not tile['impassable']:
        if tile['terrain'] != 'TERRAIN_GRASS_MOUNTAIN':
            if tile.get('feature') != 'FEATURE_GEOTHERMAL_FISSURE':
                valid_city_tiles.append((x, y))

print(f"\nValid city center tiles: {len(valid_city_tiles)}")
for t in sorted(valid_city_tiles):
    print(f"  {t}: {plots[t]}")
